type GithubOverride func(cred string, args map[string]any) (any, error)

// Github is an in-process, bring-your-own-key client.
type Github struct {
	cred      string
	http      *http.Client
	overrides map[string]GithubOverride
}

type GithubOption func(*Github)

func GithubWithHTTPClient(c *http.Client) GithubOption { return func(s *Github) { s.http = c } }

func GithubWithOverride(action string, fn GithubOverride) GithubOption {
	return func(s *Github) { s.overrides[action] = fn }
}

// NewGithub constructs a client for the given API key.
func NewGithub(credential string, opts ...GithubOption) *Github {
	s := &Github{cred: credential, http: http.DefaultClient, overrides: map[string]GithubOverride{}}
	for _, o := range opts {
		o(s)
	}
	return s
}

func (s *Github) execute(action string, args map[string]any) (any, error) {
	return ExecuteWith(s.http, GITHUB, action, args, s.cred)
}

func (s *Github) paginate(action string, args map[string]any) ([]any, error) {
	return PaginateWith(s.http, GITHUB, action, args, s.cred)
}

