// CreateGist is an ESCAPE-HATCH: register an impl with GithubWithOverride("create_gist", fn).
func (s *Github) CreateGist(args map[string]any) (any, error) {
	fn, ok := s.overrides["create_gist"]
	if !ok {
		return nil, fmt.Errorf("github.create_gist is an escape-hatch action; register an override")
	}
	return fn(s.cred, args)
}
